import React, { useEffect } from "react";
import Prism from "prismjs";
import "prismjs/themes/prism-tomorrow.css";
import "prismjs/components/prism-typescript";

interface Props {
	code: string;
	height: number | string;
}

function PrismCode(props: Props): JSX.Element {

	useEffect(() => {
		Prism.highlightAll();
	}, []);

	return (
		<div className="Code"
			style={{ width: "auto", height: props.height, whiteSpace: "pre-wrap", overflow: "auto" }}>
			<pre className="line-numbers" style={{ whiteSpace: "pre-wrap", overflow: "auto" }}>
				<code className={`language-typescript`}>{props.code}</code>
			</pre>
		</div>
	);

}

export default PrismCode;