import React, { Fragment } from "react";
import { Doughnut } from "react-chartjs-2";

const DoughnutChart = ({ labels, data, chartoptions }) => {
  const chartData = {
    labels: labels,
    datasets: [
      {
        data: data,
        backgroundColor: [
          "#FF6384",
          "#36A2EB",
          "#222222",
          "#FAC750",
          "#FFC1CE",
          "#FF6384",
          "#36A2EB",
          "#222222",
          "#FAC750",
          "#FFC1CE",
          "#FF6384",
          "#36A2EB",
          "#222222",
          "#FAC750",
          "#FFC1CE",
        ],
        hoverBackgroundColor: ["#FF6384", "#36A2EB", "#FFCE56"],
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        display: false,
        position: "",
        title: "",
      },
    },
  };

  return (
    <Fragment>
      <Doughnut
        data={chartData}
        width={chartoptions.width}
        height={chartoptions.height}
        options={options}
      />
    </Fragment>
  );
};

export default DoughnutChart;
